import{_ as e,o as r,c as a,ae as d}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Flutter SDK Overview","description":"","frontmatter":{"title":"Flutter SDK Overview","slug":"flutter-sdk"},"headers":[],"relativePath":"developer-hub/flutter-sdk.md","filePath":"developer-hub/flutter-sdk.md"}'),i={name:"developer-hub/flutter-sdk.md"};function n(o,t,s,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[d('<h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Unlock the industry&#39;s most powerful deep linking and attribution in your cross-platform Flutter app with the Branch Flutter SDK. Utilizing your native Dart code, you can accurately measure campaign performance across Android, iOS, and Web.</p><h4 id="why-use-the-branch-flutter-sdk" tabindex="-1">Why use the Branch Flutter SDK? <a class="header-anchor" href="#why-use-the-branch-flutter-sdk" aria-label="Permalink to &quot;Why use the Branch Flutter SDK?&quot;">​</a></h4><p>The Branch Flutter SDK will provide a number of benefits to your app, including:</p><ul><li>Being able to reliably deep link your users to relevant content in the app</li><li>Leveraging Branch’s attribution capabilities to determine the last touch that led to a conversion</li><li>Tracking downstream events that you can view in the Branch dashboard and attribute those events by user</li><li>Utilizing Branch’s standard events to drive ad campaign optimization</li></ul><h3 id="sdk-stats" tabindex="-1">SDK Stats <a class="header-anchor" href="#sdk-stats" aria-label="Permalink to &quot;SDK Stats&quot;">​</a></h3><ul><li><strong>Open Source Github Repo:</strong> <a href="https://github.com/BranchMetrics/flutter_branch_sdk" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/flutter_branch_sdk</a></li><li><a href="https://github.com/BranchMetrics/flutter_branch_sdk/tree/master/example" target="_blank" rel="noreferrer"><strong>Sample App</strong></a></li></ul><h3 id="functionality-support" tabindex="-1">Functionality Support <a class="header-anchor" href="#functionality-support" aria-label="Permalink to &quot;Functionality Support&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Android</th><th>iOS</th><th>Web</th></tr></thead><tbody><tr><td>Integration Validator</td><td>✅</td><td>✅</td><td>➖</td></tr><tr><td>Track users</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Enable / Disable User Tracking</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Get First and Last Parameters</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Generate Deep Link for Branch Universal Object (BUO)</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Show Share Sheet for Branch Universal Object (BUO)</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>List BUO on Search / Remove BUO from Search</td><td>✅</td><td>✅</td><td>➖</td></tr><tr><td>Register view</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Track Events</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Init Branch Session and Deep Link</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Last Attributed Touch Data</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>QR codes</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table>',9)])])}const b=e(i,[["render",n]]);export{p as __pageData,b as default};
